 23→ALFPTacticsPlayerController::ALFPTacticsPlayerController()
 24→{
 25→    TargetUnit = nullptr;
 26→    SelectedUnit = nullptr;
 27→    SelectedTile = nullptr;
 28→    bIsSelecting = false;
 29→    bIsAttacking = false;
 30→    CameraRotationPitchAngle = 60.0f;
 31→    CameraRotationYawAngle = 0.0f;
 32→    bDebugEnabled = false;
 33→    CameraOffset = FVector::ZeroVector;
 34→    bIsDragging = false;
 35→    CurrentControlState = EPlayControlState::MoveState;
 36→    LastControlState = CurrentControlState;
 37→
 38→    // 创建地图编辑器组件
 39→    MapEditorComponent = CreateDefaultSubobject<ULFPMapEditorComponent>(TEXT("MapEditorComponent"));
 40→}
