239→// 选择开始
240→void ALFPTacticsPlayerController::OnSelectStarted(const FInputActionValue& Value)
241→{
242→    bIsSelecting = true;
243→
244→    // 获取鼠标位置
245→    float MouseX, MouseY;
246→    if (GetMousePosition(MouseX, MouseY))
247→    {
248→        SelectionStart = FVector2D(MouseX, MouseY);
249→    }
250→}
