252→// 选择完成
253→void ALFPTacticsPlayerController::OnSelectCompleted(const FInputActionValue& Value)
254→{
255→    if (!bIsSelecting) return;
256→    bIsSelecting = false;
257→
258→    // 获取鼠标位置
259→    float MouseX, MouseY;
260→    GetMousePosition(MouseX, MouseY);
261→    FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
262→
263→    // 简单的点击检测（非拖拽）
264→    if (FVector2D::Distance(SelectionStart, SelectionEnd) < 10.0f)
265→    {
