216→    }
217→    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
218→
219→    // 设置移动状态
220→    CurrentTile->SetIsOccupied(false);
221→    TargetTile = NewTargetTile;
222→    CurrentPathIndex = 0;
